  1	import * as React from 'react';
  2	import {
  3	  useODFNamespaceSelector,
  4	  useODFSystemFlagsSelector,
  5	} from '@odf/core/redux';
  6	import { useGetClusterDetails } from '@odf/core/redux/utils';
  7	import { secretResource } from '@odf/core/resources';
  8	import { OCS_OPERATOR } from '@odf/shared/constants';
  9	import { BreakdownCardBody } from '@odf/shared/dashboards/breakdown-card/breakdown-body';
 10	import { LabelPadding } from '@odf/shared/dashboards/breakdown-card/breakdown-chart';
 11	import { getGroupedSelectOptions } from '@odf/shared/dashboards/breakdown-card/breakdown-dropdown';
 12	import { Colors } from '@odf/shared/dashboards/breakdown-card/consts';
 13	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
 14	import {
 15	  useCustomPrometheusPoll,
 16	  usePrometheusBasePath,
 17	} from '@odf/shared/hooks/custom-prometheus-poll';
 18	import { subscriptionResource } from '@odf/shared/resources/common';
 19	import { K8sResourceKind, SubscriptionKind } from '@odf/shared/types';
 20	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 21	import { DataPoint, getInstantVectorStats } from '@odf/shared/utils';
 22	import { humanizeBinaryBytes, isFunctionThenApply } from '@odf/shared/utils';
 23	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 24	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
 25	import * as _ from 'lodash-es';
 26	import {
 27	  Card,
 28	  CardBody,
 29	  CardHeader,
 30	  CardTitle,
 31	  MenuToggle,
 32	  MenuToggleElement,
 33	  SelectList,
 34	  Select,
 35	  SelectGroup,
 36	  SelectOption,
 37	  SelectProps,
 38	} from '@patternfly/react-core';
 39	import { ServiceType, CapacityBreakdown } from '../../../constants';
 40	import { breakdownQueryMapMCG } from '../../../queries';
 41	import { decodeRGWPrefix, getStackChartStats } from '../../../utils';
 42	import './capacity-breakdown-card.scss';
 43	
 44	type DropdownItems = {
 45	  group: string;
 46	  items: {
 47	    name: string;
 48	    id: string;
 49	    disabled: boolean;
 50	  }[];
 51	}[];
 52	
 53	const getDisableableSelectOptions = (dropdownItems: DropdownItems) => {
 54	  return dropdownItems.map(({ group, items }) => (
 55	    <SelectGroup key={group} label={group} className="co-filter-dropdown-group">
 56	      <SelectList>
 57	        {items.map(({ name, id, disabled }) => (
 58	          <SelectOption key={id} value={id} isDisabled={disabled}>
 59	            {name}
 60	          </SelectOption>
 61	        ))}
 62	      </SelectList>
 63	    </SelectGroup>
 64	  ));
 65	};
 66	
 67	type ServiceTypeProps = {
 68	  metricType: CapacityBreakdown.Metrics;
 69	  prometheusQueries?: string[];
 70	  model: K8sModel;
 71	  metric: string;
 72	  ocsVersion: string;
 73	  labelPadding: LabelPadding;
 74	};
 75	
 76	type DataPointResponse = DataPoint<string | number | Date>[][];
 77	
 78	type CapacityBreakdownCardBodyProps = ServiceTypeProps & {
 79	  response: DataPointResponse;
 80	  serviceType: ServiceType;
 81	  loading: boolean;
 82	  error: boolean;
 83	};
 84	
 85	const CapacityBreakdownCardBody: React.FC<CapacityBreakdownCardBodyProps> = ({
 86	  response,
 87	  serviceType,
 88	  loading,
 89	  error,
 90	  model,
 91	  metricType,
 92	  ocsVersion,
 93	  labelPadding,
 94	}) => {
 95	  const { t } = useCustomTranslation();
 96	
 97	  const { odfNamespace } = useODFNamespaceSelector();
 98	
 99	  // For charts whose datapoints are composed of multiple queries
100	  const flattenedResponse = response.reduce(
101	    (acc, curr, ind) => (ind < response?.length - 1 ? [...acc, ...curr] : acc),
102	    []
103	  );
104	  const top5MetricsStats = getStackChartStats(
105	    flattenedResponse,
106	    humanizeBinaryBytes,
107	    CapacityBreakdown.serviceMetricMap?.[serviceType]?.[metricType]
108	  );
109	  const totalUsed = String(response?.[response?.length - 1]?.[0]?.y);
110	
111	  const ind = top5MetricsStats.findIndex((v) => v.name === 'Others');
112	  if (ind !== -1) {
113	    top5MetricsStats[ind].name = t('Cluster-wide');
114	    top5MetricsStats[ind].link = t(
115	      'Any NON Object bucket claims that were created via an S3 client or via the NooBaa UI system.'
116	    );
117	    top5MetricsStats[ind].color = Colors.OTHER;
118	  }
119	
120	  return (
121	    <BreakdownCardBody
122	      isLoading={loading}
123	      hasLoadError={error}
124	      top5MetricsStats={top5MetricsStats}
125	      capacityUsed={totalUsed}
126	      metricTotal={totalUsed}
127	      metricModel={model}
128	      humanize={humanizeBinaryBytes}
129	      ocsVersion={ocsVersion}
130	      labelPadding={labelPadding}
131	      odfNamespace={odfNamespace}
132	    />
133	  );
134	};
135	
136	const ServiceTypeALL: React.FC<ServiceTypeProps> = ({
137	  metricType,
138	  prometheusQueries,
139	  model,
140	  metric,
141	  ocsVersion,
142	  labelPadding,
143	}) => {
144	  const [rgw, rgwLoadError, rgwLoading] = useCustomPrometheusPoll({
145	    query: prometheusQueries?.[0],
146	    endpoint: 'api/v1/query' as any,
147	    basePath: usePrometheusBasePath(),
148	  });
149	  const [noobaa, noobaaLoadError, noobaaLoading] = useCustomPrometheusPoll({
150	    query: prometheusQueries?.[1],
151	    endpoint: 'api/v1/query' as any,
152	    basePath: usePrometheusBasePath(),
153	  });
154	  const [object, objectLoadError, objectLoading] = useCustomPrometheusPoll({
155	    query: prometheusQueries?.[2],
156	    endpoint: 'api/v1/query' as any,
157	    basePath: usePrometheusBasePath(),
158	  });
159	
160	  const loading = rgwLoading || noobaaLoading || objectLoading;
161	  const error = !!rgwLoadError || !!noobaaLoadError || !!objectLoadError;
162	  const data = !!rgw && !!noobaa && !!object;
163	  const response: DataPointResponse = React.useMemo(() => {
164	    return !loading && !error && data
165	      ? [
166	          getInstantVectorStats(rgw, metric),
167	          getInstantVectorStats(noobaa, metric),
168	          getInstantVectorStats(object, metric),
169	        ]
170	      : [];
171	  }, [rgw, noobaa, object, loading, error, data, metric]);
172	
173	  return (
174	    <CapacityBreakdownCardBody
175	      response={response}
176	      serviceType={ServiceType.ALL}
177	      loading={loading}
178	      error={error}
179	      metricType={metricType}
180	      model={model}
181	      metric={metric}
182	      ocsVersion={ocsVersion}
183	      labelPadding={labelPadding}
184	    />
185	  );
186	};
187	
188	const ServiceTypeMCG: React.FC<ServiceTypeProps> = ({
189	  metricType,
190	  prometheusQueries,
191	  model,
192	  metric,
193	  ocsVersion,
194	  labelPadding,
195	}) => {
196	  const [byUsed, byUsedError, byUsedLoading] = useCustomPrometheusPoll({
197	    query: prometheusQueries?.[0],
198	    endpoint: 'api/v1/query' as any,
199	    basePath: usePrometheusBasePath(),
200	  });
201	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
202	    {
203	      query: prometheusQueries?.[1],
204	      endpoint: 'api/v1/query' as any,
205	      basePath: usePrometheusBasePath(),
206	    }
207	  );
208	
209	  const loading = byUsedLoading || totalUsedLoading;
210	  const error = !!byUsedError || !!totalUsedError;
211	  const data = !!byUsed && !!totalUsed;
212	  const response: DataPointResponse = React.useMemo(() => {
213	    return !loading && !error && data
214	      ? [
215	          getInstantVectorStats(byUsed, metric),
216	          getInstantVectorStats(totalUsed, metric),
217	        ]
218	      : [];
219	  }, [byUsed, totalUsed, loading, error, data, metric]);
220	
221	  return (
222	    <CapacityBreakdownCardBody
223	      response={response}
224	      serviceType={ServiceType.MCG}
225	      loading={loading}
226	      error={error}
227	      metricType={metricType}
228	      model={model}
229	      metric={metric}
230	      ocsVersion={ocsVersion}
231	      labelPadding={labelPadding}
232	    />
233	  );
234	};
235	
236	const ServiceTypeRGW: React.FC<ServiceTypeProps> = ({
237	  metricType,
238	  prometheusQueries,
239	  model,
240	  metric,
241	  ocsVersion,
242	  labelPadding,
243	}) => {
244	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
245	    {
246	      query: prometheusQueries?.[0],
247	      endpoint: 'api/v1/query' as any,
248	      basePath: usePrometheusBasePath(),
249	    }
250	  );
251	  const [used, usedError, usedLoading] = useCustomPrometheusPoll({
252	    query: prometheusQueries?.[1],
253	    endpoint: 'api/v1/query' as any,
254	    basePath: usePrometheusBasePath(),
255	  });
256	
257	  const loading = usedLoading || totalUsedLoading;
258	  const error = !!usedError || !!totalUsedError;
259	  const data = !!totalUsed && !!used;
260	  const response: DataPointResponse = React.useMemo(() => {
261	    return !loading && !error && data
262	      ? [
263	          getInstantVectorStats(used, metric),
264	          getInstantVectorStats(totalUsed, metric),
265	        ]
266	      : [];
267	  }, [used, totalUsed, loading, error, data, metric]);
268	
269	  return (
270	    <CapacityBreakdownCardBody
271	      response={response}
272	      serviceType={ServiceType.RGW}
273	      loading={loading}
274	      error={error}
275	      metricType={metricType}
276	      model={model}
277	      metric={metric}
278	      ocsVersion={ocsVersion}
279	      labelPadding={labelPadding}
280	    />
281	  );
282	};
283	
284	const BreakdownCard: React.FC = () => {
285	  const { t } = useCustomTranslation();
286	  const [serviceType, setServiceType] = React.useState(ServiceType.MCG);
287	  const [metricType, setMetricType] = React.useState<CapacityBreakdown.Metrics>(
288	    CapacityBreakdown.defaultMetrics[ServiceType.MCG]
289	  );
290	  const [isOpenServiceSelect, setServiceSelect] = React.useState(false);
291	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
292	
293	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
294	  const { systemFlags } = useODFSystemFlagsSelector();
295	  const isRGWSupported = systemFlags[clusterNs]?.isRGWAvailable;
296	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
297	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
298	
299	  React.useEffect(() => {
300	    if (isRGWSupported && isMCGSupported) {
301	      setServiceType(ServiceType.ALL);
302	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.ALL]);
303	    } else if (isMCGSupported) {
304	      setServiceType(ServiceType.MCG);
305	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.MCG]);
306	    } else if (isRGWSupported) {
307	      setServiceType(ServiceType.RGW);
308	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.RGW]);
309	    }
310	  }, [isRGWSupported, isMCGSupported]);
311	
312	  const [secretData, secretLoaded, secretLoadError] =
313	    useK8sWatchResource<K8sResourceKind>(secretResource(clusterNs));
314	  const rgwPrefix = React.useMemo(
315	    () =>
316	      isRGWSupported && secretLoaded && !secretLoadError
317	        ? decodeRGWPrefix(secretData)
318	        : '',
319	    [secretData, secretLoaded, secretLoadError, isRGWSupported]
320	  );
321	
322	  const { queries, model, metric } = React.useMemo(() => {
323	    const {
324	      queries: q,
325	      model: mo,
326	      metric: me,
327	    } = breakdownQueryMapMCG[serviceType][metricType] ??
328	    breakdownQueryMapMCG[serviceType][
329	      CapacityBreakdown.defaultMetrics[serviceType]
330	    ];
331	    return {
332	      queries: isFunctionThenApply(q)(rgwPrefix, managedByOCS),
333	      model: mo,
334	      metric: me,
335	    };
336	  }, [serviceType, metricType, rgwPrefix, managedByOCS]);
337	
338	  const prometheusQueries = React.useMemo(
339	    () => Object.values(queries) as string[],
340	    [queries]
341	  );
342	
343	  const [subscription, loaded, loadError] =
344	    useK8sWatchResource<SubscriptionKind>(subscriptionResource);
345	
346	  const breakdownItems = React.useMemo(
347	    () => [
348	      {
349	        group: t('Break by'),
350	        items: [
351	          {
352	            id: CapacityBreakdown.Metrics.TOTAL,
353	            name: t('Total'),
354	            disabled: false,
355	          },
356	          {
357	            id: CapacityBreakdown.Metrics.PROJECTS,
358	            name: t('Projects'),
359	            disabled: serviceType !== ServiceType.MCG,
360	          },
361	          {
362	            id: CapacityBreakdown.Metrics.BC,
363	            name: t('BucketClasses'),
364	            disabled: serviceType !== ServiceType.MCG,
365	          },
366	        ],
367	      },
368	    ],
369	    [serviceType, t]
370	  );
371	
372	  const ServiceItems = [
373	    {
374	      group: t('Service type'),
375	      items: [
376	        { name: t('All'), id: ServiceType.ALL },
377	        { name: ServiceType.MCG, id: ServiceType.MCG },
378	        { name: ServiceType.RGW, id: ServiceType.RGW },
379	      ],
380	    },
381	  ];
382	
383	  const serviceSelectItems = getGroupedSelectOptions(ServiceItems);
384	  const breakdownSelectItems = getDisableableSelectOptions(breakdownItems);
385	
386	  const handleServiceChange = (_e: React.MouseEvent, service: ServiceType) => {
387	    setServiceType(service);
388	    setMetricType(CapacityBreakdown.defaultMetrics[service]);
389	    setServiceSelect(!isOpenServiceSelect);
390	  };
391	
392	  const handleMetricsChange: SelectProps['onSelect'] = (_e, breakdown) => {
393	    setMetricType(breakdown as CapacityBreakdown.Metrics);
394	    setBreakdownSelect(!isOpenBreakdownSelect);
395	  };
396	
397	  const padding =
398	    serviceType !== ServiceType.MCG
399	      ? { top: 0, bottom: 0, left: 0, right: 50 }
400	      : undefined;
401	
402	  const ocsVersion =
403	    loaded && !loadError
404	      ? (() => {
405	          const operator = _.find(
406	            subscription,
407	            (item) => _.get(item, 'spec.name') === OCS_OPERATOR
408	          );
409	          return _.get(operator, 'status.installedCSV');
410	        })()
411	      : '';
412	
413	  const getMetricDisplayName = (metricName: string): string => {
414	    switch (metricName) {
415	      case CapacityBreakdown.Metrics.TOTAL:
416	        return 'Total';
417	      case CapacityBreakdown.Metrics.PROJECTS:
418	        return 'Projects';
419	      case CapacityBreakdown.Metrics.BC:
420	        return 'BucketClasses';
421	      default:
422	        return 'Total';
423	    }
424	  };
425	
426	  const serviceTypeToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
427	    <MenuToggle
428	      ref={toggleRef}
429	      onClick={() => setServiceSelect(!isOpenServiceSelect)}
430	      isExpanded={isOpenServiceSelect}
431	      className="nb-capacity-breakdown-card-header__dropdown nb-capacity-breakdown-card-header__dropdown--margin"
432	      aria-label={t('Service Type Dropdown Toggle')}
433	    >
434	      {t('{{serviceType}}', {
435	        serviceType,
436	      })}
437	    </MenuToggle>
438	  );
439	
440	  const breakDownToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
441	    <MenuToggle
442	      ref={toggleRef}
443	      onClick={() => setBreakdownSelect(!isOpenBreakdownSelect)}
444	      isExpanded={isOpenBreakdownSelect}
445	      className="nb-capacity-breakdown-card-header__dropdown"
446	      aria-label={t('Break By Dropdown Toggle')}
447	    >
448	      {t('{{metricName}}', { metricName: getMetricDisplayName(metricType) })}
449	    </MenuToggle>
450	  );
451	
452	  return (
453	    <Card>
454	      <CardHeader>
455	        <div className="pf-v6-u-display-flex pf-v6-u-justify-content-space-between">
456	          <CardTitle>
457	            {t('Capacity breakdown')}
458	            <FieldLevelHelp>
459	              {t(
460	                'This card shows used capacity for different resources. The available capacity is based on cloud services therefore it cannot be shown.'
461	              )}
462	            </FieldLevelHelp>
463	          </CardTitle>
464	          {isRGWSupported && isMCGSupported && (
465	            <Select
466	              isOpen={isOpenServiceSelect}
467	              onOpenChange={setServiceSelect}
468	              selected={serviceType}
469	              onSelect={handleServiceChange}
470	              aria-label={t('Service Type Dropdown')}
471	              toggle={serviceTypeToggle}
472	            >
473	              {serviceSelectItems}
474	            </Select>
475	          )}
476	          <Select
477	            isOpen={isOpenBreakdownSelect}
478	            onSelect={handleMetricsChange}
479	            selected={metricType}
480	            onOpenChange={setBreakdownSelect}
481	            aria-label={t('Break By Dropdown')}
482	            toggle={breakDownToggle}
483	          >
484	            {breakdownSelectItems}
485	          </Select>
486	        </div>
487	      </CardHeader>
488	      <CardBody className="nb-capacity-breakdown-card__body">
489	        {serviceType === ServiceType.ALL && (
490	          <ServiceTypeALL
491	            metricType={metricType}
492	            prometheusQueries={prometheusQueries}
493	            model={model}
494	            metric={metric}
495	            ocsVersion={ocsVersion}
496	            labelPadding={padding}
497	          />
498	        )}
499	        {serviceType === ServiceType.MCG && (
500	          <ServiceTypeMCG
501	            metricType={metricType}
502	            prometheusQueries={prometheusQueries}
503	            model={model}
504	            metric={metric}
505	            ocsVersion={ocsVersion}
506	            labelPadding={padding}
507	          />
508	        )}
509	        {serviceType === ServiceType.RGW && (
510	          <ServiceTypeRGW
511	            metricType={metricType}
512	            prometheusQueries={prometheusQueries}
513	            model={model}
514	            metric={metric}
515	            ocsVersion={ocsVersion}
516	            labelPadding={padding}
517	          />
518	        )}
519	      </CardBody>
520	    </Card>
521	  );
522	};
523	
524	export default BreakdownCard;

