146	    endpoint: 'api/v1/query' as any,
147	    basePath: usePrometheusBasePath(),
148	  });
149	  const [noobaa, noobaaLoadError, noobaaLoading] = useCustomPrometheusPoll({
150	    query: prometheusQueries?.[1],
151	    endpoint: 'api/v1/query' as any,
152	    basePath: usePrometheusBasePath(),
153	  });
154	  const [object, objectLoadError, objectLoading] = useCustomPrometheusPoll({
155	    query: prometheusQueries?.[2],
156	    endpoint: 'api/v1/query' as any,
157	    basePath: usePrometheusBasePath(),
158	  });
159	
160	  const loading = rgwLoading || noobaaLoading || objectLoading;
161	  const error = !!rgwLoadError || !!noobaaLoadError || !!objectLoadError;
162	  const data = !!rgw && !!noobaa && !!object;
163	  const response: DataPointResponse = React.useMemo(() => {
164	    return !loading && !error && data
165	      ? [
166	          getInstantVectorStats(rgw, metric),
167	          getInstantVectorStats(noobaa, metric),
168	          getInstantVectorStats(object, metric),
169	        ]
170	      : [];
171	  }, [rgw, noobaa, object, loading, error, data, metric]);
172	
173	  return (
174	    <CapacityBreakdownCardBody
175	      response={response}
176	      serviceType={ServiceType.ALL}
177	      loading={loading}
178	      error={error}
179	      metricType={metricType}
180	      model={model}
181	      metric={metric}
182	      ocsVersion={ocsVersion}
183	      labelPadding={labelPadding}
184	    />
185	  );
186	};
187	
188	const ServiceTypeMCG: React.FC<ServiceTypeProps> = ({
189	  metricType,
190	  prometheusQueries,
191	  model,
192	  metric,
193	  ocsVersion,
194	  labelPadding,
195	}) => {
196	  const [byUsed, byUsedError, byUsedLoading] = useCustomPrometheusPoll({
197	    query: prometheusQueries?.[0],
198	    endpoint: 'api/v1/query' as any,
199	    basePath: usePrometheusBasePath(),
200	  });
201	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
202	    {
203	      query: prometheusQueries?.[1],
204	      endpoint: 'api/v1/query' as any,
205	      basePath: usePrometheusBasePath(),
206	    }
207	  );
208	
209	  const loading = byUsedLoading || totalUsedLoading;
210	  const error = !!byUsedError || !!totalUsedError;
211	  const data = !!byUsed && !!totalUsed;
212	  const response: DataPointResponse = React.useMemo(() => {
213	    return !loading && !error && data
214	      ? [
215	          getInstantVectorStats(byUsed, metric),
216	          getInstantVectorStats(totalUsed, metric),
217	        ]
218	      : [];
219	  }, [byUsed, totalUsed, loading, error, data, metric]);
220	
221	  return (
222	    <CapacityBreakdownCardBody
223	      response={response}
224	      serviceType={ServiceType.MCG}
225	      loading={loading}
226	      error={error}
227	      metricType={metricType}
228	      model={model}
229	      metric={metric}
230	      ocsVersion={ocsVersion}
231	      labelPadding={labelPadding}
232	    />
233	  );
234	};
235	
236	const ServiceTypeRGW: React.FC<ServiceTypeProps> = ({
237	  metricType,
238	  prometheusQueries,
239	  model,
240	  metric,
241	  ocsVersion,
242	  labelPadding,
243	}) => {
244	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
245	    {
246	      query: prometheusQueries?.[0],
247	      endpoint: 'api/v1/query' as any,
248	      basePath: usePrometheusBasePath(),
249	    }
250	  );
251	  const [used, usedError, usedLoading] = useCustomPrometheusPoll({
252	    query: prometheusQueries?.[1],
253	    endpoint: 'api/v1/query' as any,
254	    basePath: usePrometheusBasePath(),
255	  });
256	
257	  const loading = usedLoading || totalUsedLoading;
258	  const error = !!usedError || !!totalUsedError;
259	  const data = !!totalUsed && !!used;
260	  const response: DataPointResponse = React.useMemo(() => {
261	    return !loading && !error && data
262	      ? [
263	          getInstantVectorStats(used, metric),
264	          getInstantVectorStats(totalUsed, metric),
265	        ]
266	      : [];
267	  }, [used, totalUsed, loading, error, data, metric]);
268	
269	  return (
270	    <CapacityBreakdownCardBody
271	      response={response}
272	      serviceType={ServiceType.RGW}
273	      loading={loading}
274	      error={error}
275	      metricType={metricType}
276	      model={model}
277	      metric={metric}
278	      ocsVersion={ocsVersion}
279	      labelPadding={labelPadding}
