284	const BreakdownCard: React.FC = () => {
285	  const { t } = useCustomTranslation();
286	  const [serviceType, setServiceType] = React.useState(ServiceType.MCG);
287	  const [metricType, setMetricType] = React.useState<CapacityBreakdown.Metrics>(
288	    CapacityBreakdown.defaultMetrics[ServiceType.MCG]
289	  );
290	  const [isOpenServiceSelect, setServiceSelect] = React.useState(false);
291	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
292	
293	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
294	  const { systemFlags } = useODFSystemFlagsSelector();
295	  const isRGWSupported = systemFlags[clusterNs]?.isRGWAvailable;
296	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
297	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
298	
299	  React.useEffect(() => {
300	    if (isRGWSupported && isMCGSupported) {
301	      setServiceType(ServiceType.ALL);
302	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.ALL]);
303	    } else if (isMCGSupported) {
304	      setServiceType(ServiceType.MCG);
305	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.MCG]);
306	    } else if (isRGWSupported) {
307	      setServiceType(ServiceType.RGW);
308	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.RGW]);
309	    }
310	  }, [isRGWSupported, isMCGSupported]);
311	
312	  const [secretData, secretLoaded, secretLoadError] =
313	    useK8sWatchResource<K8sResourceKind>(secretResource(clusterNs));
314	  const rgwPrefix = React.useMemo(
315	    () =>
316	      isRGWSupported && secretLoaded && !secretLoadError
317	        ? decodeRGWPrefix(secretData)
318	        : '',
319	    [secretData, secretLoaded, secretLoadError, isRGWSupported]
320	  );
321	
322	  const { queries, model, metric } = React.useMemo(() => {
323	    const {
324	      queries: q,
325	      model: mo,
326	      metric: me,
327	    } = breakdownQueryMapMCG[serviceType][metricType] ??
328	    breakdownQueryMapMCG[serviceType][
329	      CapacityBreakdown.defaultMetrics[serviceType]
330	    ];
331	    return {
332	      queries: isFunctionThenApply(q)(rgwPrefix, managedByOCS),
333	      model: mo,
334	      metric: me,
335	    };
336	  }, [serviceType, metricType, rgwPrefix, managedByOCS]);
337	
338	  const prometheusQueries = React.useMemo(
339	    () => Object.values(queries) as string[],
340	    [queries]
341	  );
342	
343	  const [subscription, loaded, loadError] =
344	    useK8sWatchResource<SubscriptionKind>(subscriptionResource);
345	
346	  const breakdownItems = React.useMemo(
347	    () => [
348	      {
349	        group: t('Break by'),
350	        items: [
351	          {
352	            id: CapacityBreakdown.Metrics.TOTAL,
353	            name: t('Total'),
354	            disabled: false,
355	          },
356	          {
357	            id: CapacityBreakdown.Metrics.PROJECTS,
358	            name: t('Projects'),
359	            disabled: serviceType !== ServiceType.MCG,
360	          },
361	          {
362	            id: CapacityBreakdown.Metrics.BC,
363	            name: t('BucketClasses'),
364	            disabled: serviceType !== ServiceType.MCG,
365	          },
366	        ],
367	      },
368	    ],
369	    [serviceType, t]
370	  );
371	
372	  const ServiceItems = [
373	    {
374	      group: t('Service type'),
375	      items: [
376	        { name: t('All'), id: ServiceType.ALL },
377	        { name: ServiceType.MCG, id: ServiceType.MCG },
378	        { name: ServiceType.RGW, id: ServiceType.RGW },
379	      ],
380	    },
381	  ];
382	
383	  const serviceSelectItems = getGroupedSelectOptions(ServiceItems);
384	  const breakdownSelectItems = getDisableableSelectOptions(breakdownItems);
385	
386	  const handleServiceChange = (_e: React.MouseEvent, service: ServiceType) => {
387	    setServiceType(service);
388	    setMetricType(CapacityBreakdown.defaultMetrics[service]);
389	    setServiceSelect(!isOpenServiceSelect);
390	  };
391	
392	  const handleMetricsChange: SelectProps['onSelect'] = (_e, breakdown) => {
393	    setMetricType(breakdown as CapacityBreakdown.Metrics);
394	    setBreakdownSelect(!isOpenBreakdownSelect);
395	  };
396	
397	  const padding =
398	    serviceType !== ServiceType.MCG
399	      ? { top: 0, bottom: 0, left: 0, right: 50 }
400	      : undefined;
401	
402	  const ocsVersion =
403	    loaded && !loadError
404	      ? (() => {
405	          const operator = _.find(
406	            subscription,
407	            (item) => _.get(item, 'spec.name') === OCS_OPERATOR
408	          );
409	          return _.get(operator, 'status.installedCSV');
410	        })()
411	      : '';
412	
413	  const getMetricDisplayName = (metricName: string): string => {
414	    switch (metricName) {
415	      case CapacityBreakdown.Metrics.TOTAL:
416	        return 'Total';
417	      case CapacityBreakdown.Metrics.PROJECTS:
418	        return 'Projects';
419	      case CapacityBreakdown.Metrics.BC:
420	        return 'BucketClasses';
421	      default:
422	        return 'Total';
423	    }
424	  };
425	
426	  const serviceTypeToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
427	    <MenuToggle
428	      ref={toggleRef}
429	      onClick={() => setServiceSelect(!isOpenServiceSelect)}
430	      isExpanded={isOpenServiceSelect}
431	      className="nb-capacity-breakdown-card-header__dropdown nb-capacity-breakdown-card-header__dropdown--margin"
432	      aria-label={t('Service Type Dropdown Toggle')}
433	    >
434	      {t('{{serviceType}}', {
435	        serviceType,
436	      })}
437	    </MenuToggle>
438	  );
439	
440	  const breakDownToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
441	    <MenuToggle
442	      ref={toggleRef}
443	      onClick={() => setBreakdownSelect(!isOpenBreakdownSelect)}
444	      isExpanded={isOpenBreakdownSelect}
445	      className="nb-capacity-breakdown-card-header__dropdown"
446	      aria-label={t('Break By Dropdown Toggle')}
447	    >
448	      {t('{{metricName}}', { metricName: getMetricDisplayName(metricType) })}
449	    </MenuToggle>
450	  );
451	
452	  return (
453	    <Card>
454	      <CardHeader>
455	        <div className="pf-v6-u-display-flex pf-v6-u-justify-content-space-between">
456	          <CardTitle>
457	            {t('Capacity breakdown')}
458	            <FieldLevelHelp>
459	              {t(
460	                'This card shows used capacity for different resources. The available capacity is based on cloud services therefore it cannot be shown.'
461	              )}
462	            </FieldLevelHelp>
463	          </CardTitle>
464	          {isRGWSupported && isMCGSupported && (
465	            <Select
466	              isOpen={isOpenServiceSelect}
467	              onOpenChange={setServiceSelect}
468	              selected={serviceType}
469	              onSelect={handleServiceChange}
470	              aria-label={t('Service Type Dropdown')}
471	              toggle={serviceTypeToggle}
472	            >
473	              {serviceSelectItems}
474	            </Select>
475	          )}
476	          <Select
477	            isOpen={isOpenBreakdownSelect}
478	            onSelect={handleMetricsChange}
479	            selected={metricType}
480	            onOpenChange={setBreakdownSelect}
481	            aria-label={t('Break By Dropdown')}
482	            toggle={breakDownToggle}
483	          >
484	            {breakdownSelectItems}
485	          </Select>
486	        </div>
487	      </CardHeader>
488	      <CardBody className="nb-capacity-breakdown-card__body">
489	        {serviceType === ServiceType.ALL && (
490	          <ServiceTypeALL
491	            metricType={metricType}
492	            prometheusQueries={prometheusQueries}
493	            model={model}
494	            metric={metric}
495	            ocsVersion={ocsVersion}
496	            labelPadding={padding}
497	          />
498	        )}
499	        {serviceType === ServiceType.MCG && (
500	          <ServiceTypeMCG
501	            metricType={metricType}
502	            prometheusQueries={prometheusQueries}
503	            model={model}
504	            metric={metric}
505	            ocsVersion={ocsVersion}
506	            labelPadding={padding}
507	          />
508	        )}
509	        {serviceType === ServiceType.RGW && (
510	          <ServiceTypeRGW
511	            metricType={metricType}
512	            prometheusQueries={prometheusQueries}
513	            model={model}
514	            metric={metric}
515	            ocsVersion={ocsVersion}
516	            labelPadding={padding}
517	          />
518	        )}
519	      </CardBody>
520	    </Card>
521	  );
522	};
523	
524	export default BreakdownCard;

