 83	const CapacityBreakdownCardBody: React.FC<CapacityBreakdownCardBodyProps> = ({
 84	  response,
 85	  serviceType,
 86	  loading,
 87	  error,
 88	  model,
 89	  metricType,
 90	  ocsVersion,
 91	  labelPadding,
 92	}) => {
 93	  const { t } = useCustomTranslation();
 94	
 95	  const { odfNamespace } = useODFNamespaceSelector();
 96	
 97	  // For charts whose datapoints are composed of multiple queries
 98	  const flattenedResponse = response.reduce(
 99	    (acc, curr, ind) => (ind < response?.length - 1 ? [...acc, ...curr] : acc),
100	    []
101	  );
102	  const top5MetricsStats = getStackChartStats(
103	    flattenedResponse,
104	    humanizeBinaryBytes,
105	    CapacityBreakdown.serviceMetricMap?.[serviceType]?.[metricType]
106	  );
107	  const totalUsed = String(response?.[response?.length - 1]?.[0]?.y);
108	
109	  const ind = top5MetricsStats.findIndex((v) => v.name === 'Others');
110	  if (ind !== -1) {
111	    top5MetricsStats[ind].name = t('Cluster-wide');
112	    top5MetricsStats[ind].link = t(
113	      'Any NON Object bucket claims that were created via an S3 client or via the NooBaa UI system.'
114	    );
115	    top5MetricsStats[ind].color = Colors.OTHER;
116	  }
117	
118	  return (
119	    <BreakdownCardBody
120	      isLoading={loading}
121	      hasLoadError={error}
122	      top5MetricsStats={top5MetricsStats}
123	      capacityUsed={totalUsed}
124	      metricTotal={totalUsed}
125	      metricModel={model}
126	      humanize={humanizeBinaryBytes}
127	      ocsVersion={ocsVersion}
128	      labelPadding={labelPadding}
129	      odfNamespace={odfNamespace}
130	    />
131	  );
132	};
133	
134	const ServiceTypeALL: React.FC<ServiceTypeProps> = ({
135	  metricType,
136	  prometheusQueries,
137	  model,
138	  metric,
139	  ocsVersion,
140	  labelPadding,
141	}) => {
142	  const [rgw, rgwLoadError, rgwLoading] = useCustomPrometheusPoll({
143	    query: prometheusQueries?.[0],
144	    endpoint: 'api/v1/query' as any,
145	    basePath: usePrometheusBasePath(),
146	  });
147	  const [noobaa, noobaaLoadError, noobaaLoading] = useCustomPrometheusPoll({
148	    query: prometheusQueries?.[1],
149	    endpoint: 'api/v1/query' as any,
150	    basePath: usePrometheusBasePath(),
151	  });
152	  const [object, objectLoadError, objectLoading] = useCustomPrometheusPoll({
153	    query: prometheusQueries?.[2],
154	    endpoint: 'api/v1/query' as any,
155	    basePath: usePrometheusBasePath(),
156	  });
157	
158	  const loading = rgwLoading || noobaaLoading || objectLoading;
159	  const error = !!rgwLoadError || !!noobaaLoadError || !!objectLoadError;
160	  const data = !!rgw && !!noobaa && !!object;
161	  const response: DataPointResponse = React.useMemo(() => {
162	    return !loading && !error && data
163	      ? [
164	          getInstantVectorStats(rgw, metric),
165	          getInstantVectorStats(noobaa, metric),
166	          getInstantVectorStats(object, metric),
167	        ]
168	      : [];
169	  }, [rgw, noobaa, object, loading, error, data, metric]);
170	
171	  return (
172	    <CapacityBreakdownCardBody
173	      response={response}
174	      serviceType={ServiceType.ALL}
175	      loading={loading}
176	      error={error}
177	      metricType={metricType}
178	      model={model}
179	      metric={metric}
180	      ocsVersion={ocsVersion}
181	      labelPadding={labelPadding}
182	    />
183	  );
184	};
185	
186	const ServiceTypeMCG: React.FC<ServiceTypeProps> = ({
187	  metricType,
188	  prometheusQueries,
189	  model,
190	  metric,
191	  ocsVersion,
192	  labelPadding,
193	}) => {
194	  const [byUsed, byUsedError, byUsedLoading] = useCustomPrometheusPoll({
195	    query: prometheusQueries?.[0],
196	    endpoint: 'api/v1/query' as any,
197	    basePath: usePrometheusBasePath(),
198	  });
199	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
200	    {
201	      query: prometheusQueries?.[1],
202	      endpoint: 'api/v1/query' as any,
203	      basePath: usePrometheusBasePath(),
204	    }
205	  );
206	
207	  const loading = byUsedLoading || totalUsedLoading;
208	  const error = !!byUsedError || !!totalUsedError;
209	  const data = !!byUsed && !!totalUsed;
210	  const response: DataPointResponse = React.useMemo(() => {
211	    return !loading && !error && data
212	      ? [
213	          getInstantVectorStats(byUsed, metric),
214	          getInstantVectorStats(totalUsed, metric),
215	        ]
216	      : [];
217	  }, [byUsed, totalUsed, loading, error, data, metric]);
218	
219	  return (
220	    <CapacityBreakdownCardBody
221	      response={response}
