232	};
233	
234	const ServiceTypeRGW: React.FC<ServiceTypeProps> = ({
235	  metricType,
236	  prometheusQueries,
237	  model,
238	  metric,
239	  ocsVersion,
240	  labelPadding,
241	}) => {
242	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
243	    {
244	      query: prometheusQueries?.[0],
245	      endpoint: 'api/v1/query' as any,
246	      basePath: usePrometheusBasePath(),
247	    }
248	  );
249	  const [used, usedError, usedLoading] = useCustomPrometheusPoll({
250	    query: prometheusQueries?.[1],
251	    endpoint: 'api/v1/query' as any,
252	    basePath: usePrometheusBasePath(),
253	  });
254	
255	  const loading = usedLoading || totalUsedLoading;
256	  const error = !!usedError || !!totalUsedError;
257	  const data = !!totalUsed && !!used;
258	  const response: DataPointResponse = React.useMemo(() => {
259	    return !loading && !error && data
260	      ? [
261	          getInstantVectorStats(used, metric),
262	          getInstantVectorStats(totalUsed, metric),
263	        ]
264	      : [];
265	  }, [used, totalUsed, loading, error, data, metric]);
266	
267	  return (
268	    <CapacityBreakdownCardBody
269	      response={response}
270	      serviceType={ServiceType.RGW}
271	      loading={loading}
272	      error={error}
273	      metricType={metricType}
274	      model={model}
275	      metric={metric}
276	      ocsVersion={ocsVersion}
277	      labelPadding={labelPadding}
278	    />
279	  );
280	};
