282	const BreakdownCard: React.FC = () => {
283	  const { t } = useCustomTranslation();
284	  const [serviceType, setServiceType] = React.useState(ServiceType.MCG);
285	  const [metricType, setMetricType] = React.useState<CapacityBreakdown.Metrics>(
286	    CapacityBreakdown.defaultMetrics[ServiceType.MCG]
287	  );
288	  const [isOpenServiceSelect, setServiceSelect] = React.useState(false);
289	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
290	
291	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
292	  const { systemFlags } = useODFSystemFlagsSelector();
293	  const isRGWSupported = systemFlags[clusterNs]?.isRGWAvailable;
294	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
295	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
296	
297	  React.useEffect(() => {
298	    if (isRGWSupported && isMCGSupported) {
299	      setServiceType(ServiceType.ALL);
300	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.ALL]);
301	    } else if (isMCGSupported) {
302	      setServiceType(ServiceType.MCG);
303	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.MCG]);
304	    } else if (isRGWSupported) {
305	      setServiceType(ServiceType.RGW);
306	      setMetricType(CapacityBreakdown.defaultMetrics[ServiceType.RGW]);
307	    }
308	  }, [isRGWSupported, isMCGSupported]);
309	
310	  const [secretData, secretLoaded, secretLoadError] =
311	    useK8sWatchResource<K8sResourceKind>(secretResource(clusterNs));
312	  const rgwPrefix = React.useMemo(
313	    () =>
314	      isRGWSupported && secretLoaded && !secretLoadError
315	        ? decodeRGWPrefix(secretData)
316	        : '',
317	    [secretData, secretLoaded, secretLoadError, isRGWSupported]
318	  );
319	
320	  const { queries, model, metric } = React.useMemo(() => {
321	    const {
322	      queries: q,
323	      model: mo,
324	      metric: me,
325	    } = breakdownQueryMapMCG[serviceType][metricType] ??
326	    breakdownQueryMapMCG[serviceType][
327	      CapacityBreakdown.defaultMetrics[serviceType]
328	    ];
329	    return {
330	      queries: isFunctionThenApply(q)(rgwPrefix, managedByOCS),
331	      model: mo,
332	      metric: me,
333	    };
334	  }, [serviceType, metricType, rgwPrefix, managedByOCS]);
335	
336	  const prometheusQueries = React.useMemo(
337	    () => Object.values(queries) as string[],
338	    [queries]
339	  );
340	
341	  const [subscription, loaded, loadError] =
342	    useK8sWatchResource<SubscriptionKind>(subscriptionResource);
343	
344	  const breakdownItems = React.useMemo(
345	    () => [
346	      {
347	        group: t('Break by'),
348	        items: [
349	          {
350	            id: CapacityBreakdown.Metrics.TOTAL,
351	            name: t('Total'),
352	            disabled: false,
353	          },
354	          {
355	            id: CapacityBreakdown.Metrics.PROJECTS,
356	            name: t('Projects'),
357	            disabled: serviceType !== ServiceType.MCG,
358	          },
359	          {
360	            id: CapacityBreakdown.Metrics.BC,
361	            name: t('BucketClasses'),
362	            disabled: serviceType !== ServiceType.MCG,
363	          },
364	        ],
365	      },
366	    ],
367	    [serviceType, t]
368	  );
369	
370	  const ServiceItems = [
371	    {
372	      group: t('Service type'),
373	      items: [
374	        { name: t('All'), id: ServiceType.ALL },
375	        { name: ServiceType.MCG, id: ServiceType.MCG },
376	        { name: ServiceType.RGW, id: ServiceType.RGW },
377	      ],
378	    },
379	  ];
380	
381	  const serviceSelectItems = getGroupedSelectOptions(ServiceItems);
382	  const breakdownSelectItems = getDisableableSelectOptions(breakdownItems);
383	
384	  const handleServiceChange = (_e: React.MouseEvent, service: ServiceType) => {
385	    setServiceType(service);
386	    setMetricType(CapacityBreakdown.defaultMetrics[service]);
387	    setServiceSelect(!isOpenServiceSelect);
388	  };
389	
390	  const handleMetricsChange: SelectProps['onSelect'] = (_e, breakdown) => {
391	    setMetricType(breakdown as CapacityBreakdown.Metrics);
392	    setBreakdownSelect(!isOpenBreakdownSelect);
393	  };
394	
395	  const padding =
396	    serviceType !== ServiceType.MCG
397	      ? { top: 0, bottom: 0, left: 0, right: 50 }
398	      : undefined;
399	
400	  const ocsVersion =
401	    loaded && !loadError
402	      ? (() => {
403	          const operator = _.find(
404	            subscription,
405	            (item) => _.get(item, 'spec.name') === OCS_OPERATOR
406	          );
407	          return _.get(operator, 'status.installedCSV');
408	        })()
409	      : '';
410	
411	  const getMetricDisplayName = (metricName: string): string => {
412	    switch (metricName) {
413	      case CapacityBreakdown.Metrics.TOTAL:
414	        return 'Total';
415	      case CapacityBreakdown.Metrics.PROJECTS:
416	        return 'Projects';
417	      case CapacityBreakdown.Metrics.BC:
418	        return 'BucketClasses';
419	      default:
420	        return 'Total';
421	    }
422	  };
423	
424	  const serviceTypeToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
425	    <MenuToggle
426	      ref={toggleRef}
427	      onClick={() => setServiceSelect(!isOpenServiceSelect)}
428	      isExpanded={isOpenServiceSelect}
429	      className="nb-capacity-breakdown-card-header__dropdown nb-capacity-breakdown-card-header__dropdown--margin"
430	      aria-label={t('Service Type Dropdown Toggle')}
431	    >
432	      {t('{{serviceType}}', {
433	        serviceType,
434	      })}
435	    </MenuToggle>
436	  );
437	
438	  const breakDownToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
439	    <MenuToggle
440	      ref={toggleRef}
441	      onClick={() => setBreakdownSelect(!isOpenBreakdownSelect)}
442	      isExpanded={isOpenBreakdownSelect}
443	      className="nb-capacity-breakdown-card-header__dropdown"
444	      aria-label={t('Break By Dropdown Toggle')}
445	    >
446	      {t('{{metricName}}', { metricName: getMetricDisplayName(metricType) })}
447	    </MenuToggle>
448	  );
449	
450	  return (
451	    <Card>
452	      <CardHeader>
453	        <div className="pf-v6-u-display-flex pf-v6-u-justify-content-space-between">
454	          <CardTitle>
455	            {t('Capacity breakdown')}
456	            <FieldLevelHelp>
457	              {t(
458	                'This card shows used capacity for different resources. The available capacity is based on cloud services therefore it cannot be shown.'
459	              )}
460	            </FieldLevelHelp>
461	          </CardTitle>
462	          {isRGWSupported && isMCGSupported && (
463	            <Select
464	              isOpen={isOpenServiceSelect}
465	              onOpenChange={setServiceSelect}
466	              selected={serviceType}
467	              onSelect={handleServiceChange}
468	              aria-label={t('Service Type Dropdown')}
469	              toggle={serviceTypeToggle}
470	            >
471	              {serviceSelectItems}
472	            </Select>
473	          )}
474	          <Select
475	            isOpen={isOpenBreakdownSelect}
476	            onSelect={handleMetricsChange}
477	            selected={metricType}
478	            onOpenChange={setBreakdownSelect}
479	            aria-label={t('Break By Dropdown')}
480	            toggle={breakDownToggle}
481	          >
482	            {breakdownSelectItems}
483	          </Select>
484	        </div>
485	      </CardHeader>
486	      <CardBody className="nb-capacity-breakdown-card__body">
487	        {serviceType === ServiceType.ALL && (
488	          <ServiceTypeALL
489	            metricType={metricType}
490	            prometheusQueries={prometheusQueries}
491	            model={model}
492	            metric={metric}
493	            ocsVersion={ocsVersion}
494	            labelPadding={padding}
495	          />
496	        )}
497	        {serviceType === ServiceType.MCG && (
498	          <ServiceTypeMCG
499	            metricType={metricType}
500	            prometheusQueries={prometheusQueries}
501	            model={model}
502	            metric={metric}
503	            ocsVersion={ocsVersion}
504	            labelPadding={padding}
505	          />
506	        )}
507	        {serviceType === ServiceType.RGW && (
508	          <ServiceTypeRGW
509	            metricType={metricType}
510	            prometheusQueries={prometheusQueries}
511	            model={model}
512	            metric={metric}
513	            ocsVersion={ocsVersion}
514	            labelPadding={padding}
515	          />
516	        )}
517	      </CardBody>
518	    </Card>
519	  );
520	};
521	
522	export default BreakdownCard;

